test('Logout from Multiple Sessions', async ({ page }) => {
  await page.goto('https://the-internet.herokuapp.com/login');
  await page.locator('input[name="username"]').fill('tomsmith');
  await page.locator('input[name="password"]').fill('SuperSecretPassword!');
  await page.locator('button[type="submit"]').click();
  const context = await page.context();
  const newPage = await context.newPage();
  await newPage.goto('https://the-internet.herokuapp.com/login');
  await newPage.locator('input[name="username"]').fill('tomsmith');
  await newPage.locator('input[name="password"]').fill('SuperSecretPassword!');
  await newPage.locator('button[type="submit"]').click();
  await page.locator('a[href="#"]').click();
  await expect(page.locator('h2')).toContainText('Login Page');
  await expect(newPage.locator('h2')).toContainText('Login Page');
  await expect(page.locator('div.flash.success')).toContainText('You logged out of the secure area!');
});

